"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[2331],{3468(e,n,r){r.r(n),r.d(n,{assets:()=>o,contentTitle:()=>s,default:()=>d,frontMatter:()=>l,metadata:()=>a,toc:()=>u});const a=JSON.parse('{"id":"features-usage/vehicle-settings","title":"vehicle-settings","description":"","source":"@site/docs/03-features-usage/vehicle-settings.md","sourceDirName":"03-features-usage","slug":"/features-usage/vehicle-settings","permalink":"/mhm-rentiva-docs/en/docs/next/features-usage/vehicle-settings","draft":false,"unlisted":false,"editUrl":"https://github.com/MaxHandMade/mhm-rentiva/tree/main/website/docs/03-features-usage/vehicle-settings.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"shortcodes","permalink":"/mhm-rentiva-docs/en/docs/next/features-usage/shortcodes"},"next":{"title":"Ara\xe7lar","permalink":"/mhm-rentiva-docs/en/docs/next/features-usage/vehicles"}}');var i=r(4848),t=r(8453);const l={},s=void 0,o={},u=[];function c(e){const n={code:"code",pre:"pre",...(0,t.R)(),...e.components};return(0,i.jsx)(n.pre,{children:(0,i.jsx)(n.code,{children:'---\r\nid: vehicle-settings-usage\r\ntitle: Ara\xe7 \xd6zellikleri\r\nsidebar_label: Ara\xe7 \xd6zellikleri\r\nslug: /features-usage/vehicle-settings\r\n---\r\n\r\n# Vehicle Settings Sayfas\u0131\r\n\r\n`MHM Rentiva > Vehicle Settings`, ara\xe7lar\u0131n\u0131zda hangi detaylar\u0131n, \xf6zelliklerin ve ekipmanlar\u0131n kullan\u0131laca\u011f\u0131n\u0131 yap\u0131land\u0131rd\u0131\u011f\u0131n\u0131z aland\u0131r. Bu panel sayesinde formlarda ve ara\xe7 kartlar\u0131nda gereksiz alanlar\u0131 gizleyebilir veya kendi \xf6zel alanlar\u0131n\u0131z\u0131 ekleyebilirsiniz.\r\n\r\n## Genel Bak\u0131\u015f\r\n\r\nAyarlar sayfas\u0131 \xfc\xe7 ana b\xf6l\xfcmden olu\u015fur:\r\n1.  **Vehicle Details:** Arac\u0131n temel bilgileri (Fiyat, Y\u0131l, Kilometre vb.).\r\n2.  **Vehicle Features:** Arac\u0131n konfor ve teknik \xf6zellikleri (Klima, ABS vb.).\r\n3.  **Vehicle Equipment:** Ara\xe7ta bulunan ek donan\u0131mlar (Stepne, \u0130lk Yard\u0131m Seti vb.).\r\n\r\nHer b\xf6l\xfcmde, sistemde tan\u0131ml\u0131 standart alanlar\u0131 se\xe7ip devre d\u0131\u015f\u0131 b\u0131rakabilir veya "Add Custom" \xf6zelli\u011fi ile s\u0131n\u0131rs\u0131z say\u0131da yeni alan tan\u0131mlayabilirsiniz.\r\n\r\n## 1. Vehicle Details (Ara\xe7 Detaylar\u0131)\r\n\r\nAra\xe7lar\u0131n kaydedilirken sorulacak temel sorular\u0131n\u0131 belirler.\r\n\r\n| Standart Alan | A\xe7\u0131klama |\r\n|---|---|\r\n| Price/Day | G\xfcnl\xfck kiralama bedeli. |\r\n| Year | Arac\u0131n model y\u0131l\u0131. |\r\n| Mileage | Arac\u0131n mevcut kilometresi. |\r\n| License Plate | Plaka bilgisi. |\r\n| Color | Ara\xe7 rengi. |\r\n| Brand | Marka bilgisi. |\r\n| Model | Model bilgisi. |\r\n| Seats | Koltuk say\u0131s\u0131. |\r\n| Doors | Kap\u0131 say\u0131s\u0131. |\r\n| Transmission | Vites tipi (Manual/Automatic). |\r\n| Fuel Type | Yak\u0131t tipi (Petrol/Diesel/Hybrid/Electric). |\r\n| Engine Size | Motor hacmi. |\r\n| Availability | Arac\u0131n mevcut durumu (Active/Maintenance/Inactive). |\r\n\r\n## 2. Vehicle Features (\xd6zellikler)\r\n\r\nArac\u0131n sundu\u011fu yerle\u015fik \xf6zellikleri tan\u0131mlar.\r\n\r\n- Air Conditioning\r\n- Power Steering\r\n- ABS Brakes\r\n- Airbags\r\n- Central Locking\r\n- Electric Windows\r\n- Power Mirrors\r\n- Fog Lights\r\n- Cruise Control\r\n- Bluetooth\r\n- USB Port\r\n- Navigation\r\n- Sunroof\r\n- Leather Seats\r\n- Heated Seats\r\n\r\n## 3. Vehicle Equipment (Ekipmanlar)\r\n\r\nAra\xe7la birlikte verilen ta\u015f\u0131nabilir veya sabit donan\u0131mlar\u0131 i\xe7erir.\r\n\r\n- Spare Tire (Stepne)\r\n- Jack (Kriko)\r\n- First Aid Kit (\u0130lk Yard\u0131m \xc7antas\u0131)\r\n- Fire Extinguisher (Yang\u0131n T\xfcp\xfc)\r\n- Warning Triangle (Reflekt\xf6r)\r\n- Jumper Cables (Ak\xfc Takviye Kablosu)\r\n- Ice Scraper (Buz Kaz\u0131y\u0131c\u0131)\r\n- Car Cover (Branda)\r\n- Child Seat (\xc7ocuk Koltu\u011fu)\r\n- GPS Tracker\r\n- Dashcam (Ara\xe7 Kameras\u0131)\r\n- Phone Holder (Telefon Tutucu)\r\n- Charger (\u015earj Aleti)\r\n- Cleaning Kit (Temizlik Seti)\r\n- Emergency Kit (Acil Durum Seti)\r\n\r\n## \xd6zel Alan Ekleme (Custom Fields)\r\n\r\nHer b\xf6l\xfcm\xfcn alt\u0131nda bulunan **"Add Custom"** kutucu\u011funu kullanarak kendi tan\u0131mlar\u0131n\u0131z\u0131 yapabilirsiniz.\r\n1.  Metin kutusuna \xf6zelli\u011fin ad\u0131n\u0131 yaz\u0131n (\xd6rn: "Wifi Hotspot").\r\n2.  \u0130lgili **Add Custom** butonuna t\u0131klay\u0131n.\r\n3.  Yeni alan listenin en alt\u0131na eklenecektir.\r\n4.  Kaydettikten sonra bu yeni alan t\xfcm ara\xe7 d\xfczenleme sayfalar\u0131nda g\xf6r\xfcnecektir.\r\n\r\n:::tip\r\nEkledi\u011finiz \xf6zel alanlar\u0131 daha sonra "Remove" butonu ile silebilirsiniz. Ancak bu alan\u0131 kullanan ara\xe7lardaki veriler de silinecektir.\r\n:::\r\n\r\n## Ayarlar\u0131 Kaydetme\r\n\r\nSe\xe7imlerinizi yapt\u0131ktan sonra sayfan\u0131n alt\u0131ndaki **"Save Settings"** butonuna basarak de\u011fi\u015fiklikleri kaydedin. Bu de\u011fi\u015fiklikler an\u0131nda t\xfcm sisteme yans\u0131r.\n'})})}function d(e={}){const{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(c,{...e})}):c(e)}},8453(e,n,r){r.d(n,{R:()=>l,x:()=>s});var a=r(6540);const i={},t=a.createContext(i);function l(e){const n=a.useContext(t);return a.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:l(e.components),a.createElement(t.Provider,{value:n},e.children)}}}]);